   192→  /**
   193→   * Check if category combination is allowed based on configuration
   194→   */
   195→  private isCombinationAllowed(primaryCategory: string, candidateCategory: string): boolean {
   196→    if (primaryCategory === candidateCategory) {
   197→      return true;
   198→    }
   199→
   200→    // If strict mode is enabled and combinations are specified, only allow explicit combinations
   201→    if (this.config.strictCombinationMode && this.config.allowedCombinations.length > 0) {
   202→      const combination1 = `${primaryCategory}+${candidateCategory}`;
   203→      const combination2 = `${candidateCategory}+${primaryCategory}`;
   204→      return (
   205→        this.config.allowedCombinations.includes(combination1) || this.config.allowedCombinations.includes(combination2)
   206→      );
   207→    }
   208→
   209→    // If no combinations specified, allow all (default permissive mode)
   210→    if (this.config.allowedCombinations.length === 0) {
   211→      return true;
   212→    }
   213→
   214→    // If combinations are specified but not in strict mode, still check them (current config has financial+actionable)
   215→    const combination1 = `${primaryCategory}+${candidateCategory}`;
   216→    const combination2 = `${candidateCategory}+${primaryCategory}`;
   217→    const isExplicitlyAllowed =
   218→      this.config.allowedCombinations.includes(combination1) || this.config.allowedCombinations.includes(combination2);
   219→
   220→    // Allow explicitly configured combinations, and by default allow others too (unless strict mode)
   221→    return isExplicitlyAllowed || !this.config.strictCombinationMode;
