   299→/**
   300→ * Check if there are close competing categories that AI could help disambiguate
   301→ */
   302→function checkCloseCompetitors(
   303→  candidateScores: Record<string, CandidateScore>,
   304→  primaryScore: number,
   305→  competitorGap: number = 3
   306→): boolean {
   307→  const competitors = Object.entries(candidateScores)
   308→    .map(([categoryCode, scoreData]) => ({
   309→      category: categoryCode,
   310→      score: scoreData.score || 0,
   311→    }))
   312→    .filter((cat) => cat.score > 0 && cat.score < primaryScore)
   313→    .filter((cat) => primaryScore - cat.score <= competitorGap);
   314→
   315→  return competitors.length > 0;
   316→}
