   332→  const primaryLabel = classification.selected_labels.find((l) => l.is_primary) || classification.selected_labels[0];
   333→
   334→  return {
   335→    stage_type: 'ai_routing',
   336→    stage_order: 8,
   337→    decision_factors: {
   338→      primary_score: primaryLabel?.confidence || 0,
   339→      threshold_analysis: {
   340→        high_confidence_threshold: thresholds.high_confidence_threshold,
   341→        ai_required_threshold: thresholds.ai_required_threshold,
   342→        low_confidence_threshold: thresholds.low_confidence_threshold,
   343→        primary_score: primaryLabel?.confidence || 0,
   344→        threshold_met: primaryLabel?.confidence >= thresholds.ai_required_threshold ? 'ai_required' : 'below_threshold',
   345→      },
   346→      competitor_analysis: {
   347→        close_competitors_found: checkCloseCompetitors(classification.candidate_scores, primaryLabel?.confidence || 0),
   348→        competitor_count: Object.keys(classification.candidate_scores).length - 1,
   349→        multiple_labels_selected: classification.selected_labels.length > 1,
   350→      },
   351→    },
   352→    reasoning: routingDecision.routing_reason,
   353→    processing_metadata: {
   354→      processing_time_ms: processingTime,
   355→      input_labels_count: classification.selected_labels.length,
   356→      candidate_scores_count: Object.keys(classification.candidate_scores).length,
   357→    },
   358→  };
   359→}
   360→

