      const responseWithFakeEvidence = {
        semantic_intent: {
          primary_purpose: 'notification',
          action_required: 'view',
          urgency_level: 'high',
        },
        category_enhancements: {
          financial: {
            applies: true,
            confidence_boost: 0.9,
            evidence: {
              quoted_phrases: ['payment due', 'credit card bill'], // These DON'T exist in email
              keywords: ['payment', 'credit'],
              reasoning: 'Contains payment and credit references',
            },
          },
        },
      };

      const mockOpenAI = require('openai').OpenAI;
      mockOpenAI.prototype.chat.completions.create = jest.fn().mockResolvedValue({
        choices: [{ message: { content: JSON.stringify(responseWithFakeEvidence) } }],
        usage: { total_tokens: 180 },
      });

      const result = await aiFeatureExtractionStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockDetectedAttributes,
        mockConfig
      );

      expect(result.evidenceValidation.invalidPhrases).toContain('payment due');
      expect(result.evidenceValidation.invalidPhrases).toContain('credit card bill');
      expect(result.evidenceValidation.fabricationDetected).toBe(true);
    });
  });
});

