        mockSession,
        mockCandidateCategories,
        mockDetectedAttributes,
        mockConfig
      );

      expect(result.processingDurationMs).toBeGreaterThan(0);
      expect(result.processingDurationMs).toBeLessThan(5000);
      expect(result.tokenUsage).toBe(275);
      expect(result.apiCallCount).toBe(1);
    });

    it('should meet performance targets for single email processing', async () => {
      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
              content: JSON.stringify({
                semantic_intent: {
                  primary_purpose: 'notification',
                  action_required: 'none',
                  urgency_level: 'low',
                },
                category_enhancements: {},
              }),
            },
          },
        ],
        usage: { total_tokens: 150 },
