 *
 * This stage is responsible for:
 * - Calling OpenAI API with structured prompts and email content
 * - Validating AI responses against JSON schema
 * - Extracting semantic intent and category enhancements
 * - Validating evidence grounding (quoted phrases must exist in email)
 * - Providing retry logic and error handling for API failures
 * - Supporting batch processing with concurrent API calls
 */

import { OpenAI } from 'openai';
import Ajv from 'ajv';
import { EmailMessage, ClassificationSession } from '../types';

// Configuration interface for AI feature extraction
export interface AIFeatureExtractionConfig {
  openai: {
    apiKey: string;
    model: string;
    temperature: number;
    responseFormat: string;
  };
  prompts: {
    systemPrompt: string[];
    userPrompt: string[];
  };
  featureExtractionSchema: object;
  retryPolicy: {
    maxRetries: number;
    backoffMs: number;
  };
}

// Semantic intent extracted by AI
export interface SemanticIntent {
  primary_purpose: 'notification' | 'request' | 'update' | 'alert';
  action_required: 'none' | 'view' | 'respond' | 'complete';
  urgency_level: 'none' | 'low' | 'medium' | 'high';
}

// Evidence structure for category enhancements
export interface CategoryEvidence {
  quoted_phrases: string[];
  keywords: string[];
  reasoning: string;
}

// Category enhancement from AI analysis
export interface CategoryEnhancement {
  applies: boolean;
  confidence_boost: number;
  evidence: CategoryEvidence;
}

// Complete feature extraction result from AI
export interface FeatureExtractionData {
  semantic_intent: SemanticIntent;
  category_enhancements: Record<string, CategoryEnhancement>;
}

// Evidence validation result
export interface EvidenceValidation {
  validPhrases: string[];
  invalidPhrases: string[];
  fabricationDetected: boolean;
}

// Complete stage result interface
export interface FeatureExtractionResult {
  featureExtraction: FeatureExtractionData;
  validationPassed: boolean;
  validationErrors: string[];
  evidenceValidation: EvidenceValidation;
  processingDurationMs: number;
  tokenUsage: number;
  apiCallCount: number;
  retryCount: number;
}

/**
 * AI Feature Extraction Stage Implementation
 *
 * Integrates with OpenAI GPT-4o-mini to extract semantic features and enhance
 * category classifications with evidence-grounded analysis.
 */
export async function aiFeatureExtractionStage(
  email: EmailMessage,
  session: ClassificationSession,
  candidateCategories: Record<string, unknown>,
  detectedAttributes: Record<string, unknown>,
  config: AIFeatureExtractionConfig
): Promise<FeatureExtractionResult> {
  const startTime = Date.now();
  let retryCount = 0;
  let apiCallCount = 0;

  // Validate inputs
  validateInputs(email, session, config);

  // Initialize OpenAI client
  const openai = new OpenAI({
    apiKey: config.openai.apiKey,
  });

  // Setup JSON schema validator
  const ajv = new Ajv();
  const validateSchema = ajv.compile(config.featureExtractionSchema);

  // Retry loop for API calls
  let lastError: Error | null = null;

  while (retryCount < config.retryPolicy.maxRetries) {
    try {
      apiCallCount++;

      // Prepare prompts with email content interpolation
      const systemPrompt = config.prompts.systemPrompt.join('\n');
      const userPrompt = interpolateUserPrompt(
        config.prompts.userPrompt,
        email,
        candidateCategories,
        detectedAttributes
      );

      // Call OpenAI API
      const response = await openai.chat.completions.create({
        model: config.openai.model,
        temperature: config.openai.temperature,
        response_format: { type: config.openai.responseFormat as 'json_object' },
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt },
        ],
      });

      // Parse and validate response
      const rawContent = response.choices[0].message.content;
      if (!rawContent) {
        throw new Error('Empty response from OpenAI');
      }

      let featureExtractionData: FeatureExtractionData;
      try {
        featureExtractionData = JSON.parse(rawContent);
      } catch {
        throw new Error('Invalid JSON response from OpenAI');
      }

      // Validate against schema
      const validationPassed = validateSchema(featureExtractionData);
      const validationErrors: string[] = [];

      if (!validationPassed && validateSchema.errors) {
        for (const error of validateSchema.errors) {
          validationErrors.push(`${error.instancePath} ${error.message}`);
        }
        throw new Error('Schema validation failed: ' + validationErrors.join(', '));
      }

      // Validate evidence grounding
      const evidenceValidation = validateEvidenceGrounding(email, featureExtractionData);

      // Success - return result
      return {
        featureExtraction: featureExtractionData,
        validationPassed: true,
        validationErrors: [],
        evidenceValidation,
        processingDurationMs: Date.now() - startTime,
        tokenUsage: response.usage?.total_tokens || 0,
        apiCallCount,
        retryCount,
      };
    } catch (error) {
      lastError = error as Error;
      retryCount++;

      if (retryCount < config.retryPolicy.maxRetries) {
        // Wait before retry with exponential backoff
        await new Promise((resolve) => setTimeout(resolve, config.retryPolicy.backoffMs * Math.pow(2, retryCount - 1)));
      }
    }
  }

  // All retries exhausted
  throw new Error(`AI feature extraction failed after ${config.retryPolicy.maxRetries} retries: ${lastError?.message}`);
}

/**
 * Validate input parameters
 */
function validateInputs(email: EmailMessage, session: ClassificationSession, config: AIFeatureExtractionConfig): void {
  if (!email?.id && !('gmail_id' in email)) {
    throw new Error('Invalid email input: id or gmail_id is required');
  }

  if (!email.subject) {
    throw new Error('Invalid email input: subject is required');
  }

  if (!session?.id && !('session_id' in session)) {
    throw new Error('Invalid session input: id or session_id is required');
  }

  if (!config) {
    throw new Error('Configuration is required');
  }

  if (!config.openai?.apiKey || config.openai.apiKey.trim() === '') {
    throw new Error('Invalid configuration: OpenAI API key is required');
  }

  if (!config.prompts?.systemPrompt || !config.prompts?.userPrompt) {
    throw new Error('Invalid configuration: system and user prompts are required');
  }

  if (!config.featureExtractionSchema) {
    throw new Error('Invalid configuration: feature extraction schema is required');
  }
}

/**
 * Interpolate user prompt template with email content and analysis data
 */
function interpolateUserPrompt(
  userPromptTemplate: string[],
  email: EmailMessage,
  candidateCategories: Record<string, unknown>,
  detectedAttributes: Record<string, unknown>
): string {
  const template = userPromptTemplate.join('\n');

  return template
    .replace('{from}', formatEmailAddress(email.from))
    .replace('{subject}', email.subject || '')
    .replace('{body}', getEmailBodyText(email))
    .replace('{candidateCategories}', JSON.stringify(candidateCategories))
    .replace('{detectedAttributes}', JSON.stringify(detectedAttributes));
}

/**
 * Format email address for prompt display
 */
function formatEmailAddress(address: any): string {
  if (!address) return 'Unknown';

  if (typeof address === 'string') return address;

  if (address.name && address.email) {
    return `${address.name} <${address.email}>`;
  }

  return address.email || address.raw || 'Unknown';
}

/**
 * Extract email body text (prefer plain text, fallback to HTML)
 */
function getEmailBodyText(email: EmailMessage): string {
  if (email.bodyPlain) {
    return email.bodyPlain;
  }

  if (email.bodyHtml) {
    // Simple HTML tag removal for prompt purposes
    return email.bodyHtml.replace(/<[^>]*>/g, '').trim();
  }

  return '[No body content available]';
}

/**
 * Validate that quoted phrases in evidence actually exist in the email content
 */
function validateEvidenceGrounding(email: EmailMessage, featureExtraction: FeatureExtractionData): EvidenceValidation {
  const emailText = (email.subject + ' ' + getEmailBodyText(email)).toLowerCase();
  const validPhrases: string[] = [];
  const invalidPhrases: string[] = [];

  // Check all quoted phrases in category enhancements
  for (const [categoryName, enhancement] of Object.entries(featureExtraction.category_enhancements || {})) {
    if (enhancement.evidence?.quoted_phrases) {
      for (const phrase of enhancement.evidence.quoted_phrases) {
        const normalizedPhrase = phrase.toLowerCase().trim();
        if (normalizedPhrase && emailText.includes(normalizedPhrase)) {
          validPhrases.push(phrase);
        } else if (normalizedPhrase) {
          invalidPhrases.push(phrase);
        }
      }
    }
  }

  return {
    validPhrases,
    invalidPhrases,
    fabricationDetected: invalidPhrases.length > 0,
  };
}

